const mc = $('Get Mission Control').first().json;
const autonomy = $('Get AI ROI Report').first().json;
const portfolio = $('Get Portfolio Status').first().json;
const now = new Date();
const today = now.toISOString().split('T')[0];
const monthYear = now.toLocaleString('en-US', { month: 'long', year: 'numeric' });
// Previous month label
const prevMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1)
  .toLocaleString('en-US', { month: 'long', year: 'numeric' });

// Company health
const healthIcon = h => h === 'GREEN' ? '🟢' : h === 'YELLOW' ? '🟡' : h === 'RED' ? '🔴' : '⚪';
const coHealth = mc.company_health || portfolio.company_health || 'UNKNOWN';

// Portfolio table
const projects = portfolio.projects || mc.portfolio?.projects || [];
const projectLines = projects.map(p => {
  const health = p.health || 'UNKNOWN';
  const risk = p.risk_count ?? p.open_risks ?? 0;
  const decisions = p.open_decisions ?? 0;
  const budget = p.budget_exposure != null ? `$${p.budget_exposure.toLocaleString()}` : '—';
  return `| ${p.project_code || '—'} | ${p.project_name || p.name} | ${healthIcon(health)} ${health} | ${risk} | ${decisions} | ${budget} |`;
}).join('\n');

// AI ROI
const roi = autonomy.executive_summary || {};
const hoursSaved = roi.hours_saved_this_week || 0;
const docsProcessed = roi.documents_processed || 0;
const risksDetected = roi.risks_detected || 0;
const workflowRuns = roi.workflow_runs || 0;
const top3 = autonomy.top_3_opportunities || [];
const top3Lines = top3.map((o, i) =>
  `${i + 1}. **${o.title}** — ${o.roi_hours_per_week || 0}h/wk ROI\n   ${o.why || ''}`
).join('\n\n');

// Missions
const missions = mc.ai_missions || {};
const missionCounts = missions.counts || {};
const completeRate = missions.active_missions
  ? Math.round((missionCounts.completed || 0) / Math.max((missionCounts.completed || 0) + (missionCounts.in_progress || 0) + (missionCounts.blocked || 0) + (missionCounts.open_q || 0), 1) * 100)
  : 0;

// System health from MC
const sysHealth = mc.system_health || {};

const md = `# HCI Monthly Business Review
**${prevMonth} Review** | Generated ${today}

---

## Company Portfolio — ${healthIcon(coHealth)} ${coHealth}

| Code | Project | Health | Risks | Decisions | Budget Exposure |
|------|---------|--------|-------|-----------|----------------|
${projectLines || '| — | — | — | — | — | — |'}

**Active Projects:** ${portfolio.active_projects || projects.length} | **At Risk:** ${portfolio.projects_at_risk || 0}

---

## AI ROI — ${prevMonth}

| Metric | This Period |
|--------|-------------|
| Hours saved by automation | **${hoursSaved}h** |
| Documents processed | ${docsProcessed} |
| Risks auto-detected | ${risksDetected} |
| Workflow runs | ${workflowRuns} |

### Top Automation Opportunities for Next Month

${top3Lines || '_No new opportunities ranked_'}

---

## Mission Control Summary

| Status | Count |
|--------|-------|
| In Progress | ${missionCounts.in_progress || 0} |
| Blocked | ${missionCounts.blocked || 0} |
| Open Questions | ${missionCounts.open_q || 0} |
| Completed | ${missionCounts.completed || 0} |

**Mission completion rate:** ${completeRate}%

${(missionCounts.blocked || 0) > 0 ? `\n⛔ **${missionCounts.blocked} mission(s) blocked — review required**` : '✅ No missions blocked'}

---

## Executive Inbox

**${mc.inbox?.pending_count || 0} item(s) pending approval**

---

## Decisions Made This Month

_Review architecture/CHANGELOG.md for architectural decisions and ADRs filed._

---

## Next Month Priorities

1. ${(missionCounts.blocked || 0) > 0 ? 'Unblock ' + missionCounts.blocked + ' blocked mission(s)' : 'Continue current mission roadmap'}
2. ${(portfolio.projects_at_risk || 0) > 0 ? 'Resolve ' + portfolio.projects_at_risk + ' at-risk project(s)' : 'Maintain project health'}
3. ${top3[0] ? 'Evaluate: ' + top3[0].title + ' (' + (top3[0].roi_hours_per_week || 0) + 'h/wk ROI)' : 'Review automation backlog'}

---
*Generated by AUTO-MONTHLY-REVIEW | HCI AI OS | ${new Date().toISOString()}*`;

const pushMsg = `📅 ${prevMonth} Review: ${healthIcon(coHealth)} ${coHealth} portfolio | AI saved ${hoursSaved}h | Missions: ${missionCounts.completed || 0} complete, ${missionCounts.blocked || 0} blocked | ${portfolio.projects_at_risk || 0} projects at risk`;

return [{ json: {
  md,
  pushMsg,
  company_health: coHealth,
  hours_saved: hoursSaved,
  missions_blocked: missionCounts.blocked || 0,
  projects_at_risk: portfolio.projects_at_risk || 0,
  filename: `reports/monthly/exec-review-${today.slice(0, 7)}.md`
}}];

